_StereoVideo.vertexProgram:
varying vec2 Texcoord;


    void main( void )
    {
             Texcoord = gl_MultiTexCoord0;
	    gl_Position = ftransform();	
    }

_StereoVideo.fragmentProgram:
varying vec2 Texcoord;
    uniform sampler2D diffuseMap;

    uniform int Stereo;

    void main( void )
    {
    vec2 tcl = Texcoord;
    vec2 tcr = Texcoord;
    tcr.x = Texcoord.x*0.5;
    tcl.y = -tcl.y;
    tcl.x = Texcoord.x*0.5-0.5;
    tcr.y = -tcr.y;
    //tcr.x = (Texcoord.x+0.5)*0.5;
    if(Stereo==1) //right
      gl_FragColor = texture2D( diffuseMap, tcr );
    else          //left
      gl_FragColor = texture2D( diffuseMap, tcl );

    }
